import { Grid } from "@mui/material";
import CssBaseline from "@mui/material/CssBaseline"
import Barra from "../../Commons/Barra/Barra";
import { CopyRight } from "../../Commons/Copyright";
import VideoLanding from "../../Components/VideosDep/VideoLanding";
import CarrilProductos from "../../Components/Itemslanding/CarrilProductos";

export default function ButtonAppBar() {
  return (
    <>
      <CssBaseline/>
      <Barra/>
      <Grid container xs={12} sx={{display:"flex", flexDirection:"column"}}>
        <Grid item>
          <VideoLanding/>
        </Grid>
        <Grid item>
         hola
        </Grid>
        <Grid item>
        <p>Para producto 2</p>
        </Grid>
        <Grid item>
        <p>Para producto quienes somos</p>
        </Grid>
        <Grid item>
        <p>Para producto nustro trabajo</p>
        </Grid>
      </Grid>
      <CopyRight/>
    </>
  );
}
